// Parse --find-new JSON output and split into one item per request
const stdout = $input.first().json.stdout;
let data;
try {
  data = JSON.parse(stdout);
} catch (e) {
  return [{ json: { count: 0, error: 'Failed to parse find-new output: ' + e.message } }];
}

if (!data.count || data.count === 0) {
  return [{ json: { count: 0 } }];
}

// Output one item per request — Run Pipeline processes each
return data.requests.map(r => ({
  json: {
    request_id: r.id,
    title: r.title,
    company: r.company,
    launch_date: r.launch_date,
    count: data.count
  }
}));

// Aggregate results from ALL pipeline runs into sheet-ready data
const pipelineOutputs = $input.all();
const requestInputs = $('Parse New Requests').all();

const allQueryRows = [];
const allCoverageRows = [];
const allMetadataRows = [];
const summaryParts = [];
let totalProcessed = 0;
let totalFailed = 0;

for (let i = 0; i < pipelineOutputs.length; i++) {
  const output = pipelineOutputs[i].json;
  const reqMeta = requestInputs[i] ? requestInputs[i].json : {};
  const company = reqMeta.company || '';

  // Check for execution failure
  if (output.error || !output.stdout) {
    totalFailed++;
    summaryParts.push(
      `\u274c #${reqMeta.request_id || '?'} — ${reqMeta.title || '?'} (${company}): Pipeline failed`
    );
    continue;
  }

  let data;
  try {
    data = JSON.parse(output.stdout);
  } catch (e) {
    totalFailed++;
    summaryParts.push(
      `\u274c #${reqMeta.request_id || '?'}: JSON parse error — ${e.message}`
    );
    continue;
  }

  totalProcessed++;
  const stats = data.stats || {};
  const reqId = data.request_id || reqMeta.request_id || '?';
  const reqTitle = data.request_title || reqMeta.title || 'Unknown';

  // --- Query rows ---
  for (const q of data.valid_queries || []) {
    allQueryRows.push({
      'Request ID': reqId,
      'Request Title': reqTitle,
      'Query': q.query,
      'Result Count': q.result_count,
      'Category': q.category || '',
      'Status': 'valid',
      'SOI Covered': q.target_soi,
      'Rationale': q.rationale,
      'Relevance Passed': q.relevance_passed ? 'True' : 'False',
      'Relevance Details': q.relevance_details || '',
      'Refinement Round': q.refinement_round || 0,
      'Original Query': q.original_query || '',
      'Reviewer Verdict': '',
      'Reviewer Notes': ''
    });
  }

  for (const q of data.unvalidated_queries || []) {
    allQueryRows.push({
      'Request ID': reqId,
      'Request Title': reqTitle,
      'Query': q.query,
      'Result Count': '',
      'Category': '',
      'Status': 'unvalidated \u2014 needs manual S2 check',
      'SOI Covered': q.target_soi,
      'Rationale': q.rationale,
      'Relevance Passed': '',
      'Relevance Details': 'S2 API unreachable during validation',
      'Refinement Round': q.refinement_round || 0,
      'Original Query': q.original_query || '',
      'Reviewer Verdict': '',
      'Reviewer Notes': ''
    });
  }

  // --- Coverage rows ---
  for (const cov of data.soi_coverage || []) {
    allCoverageRows.push({
      'Request ID': reqId,
      'Request Title': reqTitle,
      'Solution of Interest': cov.soi,
      '# Queries': cov.num_queries,
      'Best Query': cov.best_query,
      'Best Result Count': cov.best_result_count || 0
    });
  }

  // --- Metadata row ---
  allMetadataRows.push({
    'Run ID': data.run_id,
    'Request ID': reqId,
    'Request Title': reqTitle,
    'Company': company,
    'Started At': data.started_at,
    'Completed At': data.completed_at,
    'Model Used': data.model_used,
    'Total Generated': stats.total_generated || 0,
    'Valid': stats.valid || 0,
    'Unvalidated': stats.unvalidated || 0,
    'Rejected Broad': stats.rejected_too_broad || 0,
    'Rejected Irrelevant': stats.rejected_irrelevant || 0,
    'SOIs Covered': `${stats.sois_covered || 0}/${stats.sois_total || 0}`
  });

  // Summary line for Slack
  const cat = stats.by_category || {};
  summaryParts.push(
    `\u2705 #${reqId} \u2014 ${reqTitle} (${company})\n` +
    `   Valid: ${stats.valid || 0}/${stats.total_generated || 0}` +
    (stats.unvalidated ? ` (${stats.unvalidated} unvalidated)` : '') +
    ` | SOIs: ${stats.sois_covered || 0}/${stats.sois_total || 0}` +
    ` | HS:${cat.highly_specific||0} S:${cat.specific||0} M:${cat.moderate||0} G:${cat.general||0}`
  );
}

// Build Slack message
const slackMessage = `:mag: *RoboScout Daily Digest*\n` +
  `*${totalProcessed} requests processed*` +
  (totalFailed ? ` (${totalFailed} failed)` : '') +
  `\n\n` +
  summaryParts.join('\n') +
  `\n\n:bar_chart: <https://docs.google.com/spreadsheets/d/1MvQXMXLyyNMs2bfWg1JsSRLBfOGVF7Z5nPlj9fED-bU|Review in Google Sheets>`;

return [{
  json: {
    queryRows: allQueryRows,
    coverageRows: allCoverageRows,
    metadataRows: allMetadataRows,
    slackMessage,
    totalProcessed,
    totalFailed
  }
}];

// Convert queryRows array into n8n items for Google Sheets append
const data = $('Aggregate Results').first().json;
const rows = data.queryRows || [];
if (rows.length === 0) {
  return $input.all(); // passthrough to keep chain alive
}
return rows.map(row => ({ json: row }));

// Convert coverageRows array into n8n items for Google Sheets append
const data = $('Aggregate Results').first().json;
const rows = data.coverageRows || [];
if (rows.length === 0) {
  return $input.all(); // passthrough to keep chain alive
}
return rows.map(row => ({ json: row }));

// Convert metadataRows array into n8n items for Google Sheets append
const data = $('Aggregate Results').first().json;
const rows = data.metadataRows || [];
if (rows.length === 0) {
  return $input.all(); // passthrough to keep chain alive
}
return rows.map(row => ({ json: row }));

// Get the pre-built Slack message from Aggregate Results
const data = $('Aggregate Results').first().json;
return [{ json: { message: data.slackMessage } }];
